INSERT INTO `assessment_scale` VALUES (2,'phq-9','PHQ-9抑郁量表','https://mindease-oss.oss-cn-shanghai.aliyuncs.com/2025/12/e7b4aedf-0805-4037-9078-231695d0de93.png','PHQ-9是20世纪90年代由哥伦比亚大学依据DSM-IV抑郁症的9项症状标准编写出的九条目自我测试工具。相对与SDS自评量表，PHQ-9因简单易懂，操作方便，易掌握等优点被美国预防服务工作组（USPSTF）等机构推荐用于筛查抑郁症。','[{\"max\": 1, \"min\": 0, \"desc\": \"挺好\", \"level\": \"好\"}, {\"max\": 3, \"min\": 2, \"desc\": \"不好啊\", \"level\": \"不好\"}]','active'),(3,'gad-7','GAD-7焦虑症筛查表','https://mindease-oss.oss-cn-shanghai.aliyuncs.com/2025/12/790b79dd-cc32-49e5-918c-069c725be33a.png','7 项广泛性焦虑障碍量表（generalized anxiety disorder-7, GAD-7）是由 Spitzer 等人于2006年编制的简明焦虑症状自评量表。GAD-7为自评量表，由被评价者亲自填写，主要根据最近2周出现表1 症状的天数填写。','[{\"max\": 4, \"min\": 0, \"desc\": \"您的情绪状态良好，请继续保持。\", \"level\": \"没有焦虑\"}, {\"max\": 9, \"min\": 5, \"desc\": \"建议适当进行放松训练。\", \"level\": \"轻度焦虑\"}, {\"max\": 14, \"min\": 10, \"desc\": \"建议寻求心理咨询师帮助。\", \"level\": \"中度焦虑\"}, {\"max\": 21, \"min\": 15, \"desc\": \"强烈建议前往医院就诊。\", \"level\": \"重度焦虑\"}]','active'),(5,'custom-1765884763455','新建量表测试','https://mindease-oss.oss-cn-shanghai.aliyuncs.com/2025/12/6ac72477-c37b-4cb2-8a0a-41a5b0532837.png','测试 新建了一个量表','[]','active'),(6,'custom-1765885878289','测试量表2','https://mindease-oss.oss-cn-shanghai.aliyuncs.com/2025/12/1b6605e2-6de8-493d-b604-c86a6535f012.png','这是一个测试量表','[]','active'),(7,'custom-1765885881605','测试量表3','https://mindease-oss.oss-cn-shanghai.aliyuncs.com/2025/12/5f66f321-0e69-47cb-b7e2-403502360044.png','这是一个测试量表3','[]','active');
